/** Generic MCP icon for custom/unknown providers */
export function McpGenericIcon({
  className = "size-5",
}: {
  className?: string;
}) {
  return (
    <span
      className={`inline-flex items-center justify-center rounded-[4px] bg-muted border border-border/50 ${className}`}
    >
      <svg
        viewBox="0 0 24 24"
        className="h-[55%] w-[55%]"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
        strokeLinejoin="round"
      >
        <rect x="2" y="6" width="7" height="7" rx="1" />
        <rect x="9" y="2" width="7" height="7" rx="1" />
        <rect x="15" y="11" width="7" height="7" rx="1" />
        <rect x="9" y="15" width="7" height="7" rx="1" />
      </svg>
    </span>
  );
}

/** Get the appropriate icon component for a provider */
export function McpProviderIcon({
  provider,
  className = "size-5",
}: {
  provider: string;
  className?: string;
}) {
  switch (provider) {
    case "granola":
      return <GranolaIcon className={className} />;
    case "notion":
      return <NotionIcon className={className} />;
    default:
      return <McpGenericIcon className={className} />;
  }
}
